func main() {
	port := os.Getenv("PORT")
	if port == "" {
		port = "50051"
	}

	listener, err := net.Listen("tcp", ":"+port)
	if err != nil {
		log.Fatalf("Failed to listen on port %s: %v", port, err)
	}

	grpcServer := grpc.NewServer()

	productService := &ProductServiceServer{}
	orderService := &OrderServiceServer{}
	userService := &UserServiceServer{}

	grpcServer.RegisterService(&ProductService_ServiceDesc, productService)
	grpcServer.RegisterService(&OrderService_ServiceDesc, orderService)
	grpcServer.RegisterService(&UserService_ServiceDesc, userService)

	healthServer := health.NewServer()
	grpc_health_v1.RegisterHealthServer(grpcServer, healthServer)
	healthServer.SetServingStatus("microservices.ProductService", grpc_health_v1.HealthCheckResponse_SERVING)
	healthServer.SetServingStatus("microservices.OrderService", grpc_health_v1.HealthCheckResponse_SERVING)
	healthServer.SetServingStatus("microservices.UserService", grpc_health_v1.HealthCheckResponse_SERVING)
	healthServer.SetServingStatus("", grpc_health_v1.HealthCheckResponse_SERVING)

	reflection.Register(grpcServer)

	log.Printf("Starting gRPC server on port %s with reflection enabled", port)
	log.Println("Reflection is enabled in all environments for easier debugging and testing")
	log.Println("Registered services:")
	log.Println("  - microservices.ProductService")
	log.Println("  - microservices.OrderService")
	log.Println("  - microservices.UserService")
	log.Println("  - grpc.health.v1.Health")
	log.Println("  - grpc.reflection.v1alpha.ServerReflection")

	go func() {
		if err := grpcServer.Serve(listener); err != nil {
			log.Fatalf("Failed to serve: %v", err)
		}
	}()

	quit := make(chan os.Signal, 1)
	signal.Notify(quit, syscall.SIGINT, syscall.SIGTERM)
	<-quit

	log.Println("Shutting down gRPC server...")
	grpcServer.GracefulStop()
	log.Println("Server stopped")
}